const express = require('express');
const http    = require('http');
const path    = require('path');
const fs      = require('fs');
const os      = require('os');

const app    = express();
const server = http.createServer(app);
app.use(express.json());

// ── HTML 내장 (base64) ──
const INDEX_HTML_B64   = '';
const ADMIN_HTML_B64   = '';
const DISPLAY_HTML_B64 = '';

const INDEX_HTML   = Buffer.from(INDEX_HTML_B64,   'base64').toString('utf8');
const ADMIN_HTML   = Buffer.from(ADMIN_HTML_B64,   'base64').toString('utf8');
const DISPLAY_HTML = Buffer.from(DISPLAY_HTML_B64, 'base64').toString('utf8');

function serveMain(req, res)    { res.setHeader('Content-Type','text/html;charset=utf-8'); res.send(INDEX_HTML); }
function serveAdmin(req, res)   { res.setHeader('Content-Type','text/html;charset=utf-8'); res.send(ADMIN_HTML); }
function serveDisplay(req, res) { res.setHeader('Content-Type','text/html;charset=utf-8'); res.send(DISPLAY_HTML); }

app.get('/',            serveMain);
app.get('/index.html',  serveMain);
app.get('/admin',       serveAdmin);
app.get('/admin.html',  serveAdmin);
app.get('/display',     serveDisplay);
app.get('/screen',      serveDisplay);

app.use(express.static(path.join(__dirname, 'public'), { index: false }));

app.get('/version', (req, res) => res.json({ version: 'v7.0', time: new Date().toISOString() }));

// ── 설정 ──
const TIME_LIMIT_MS = 30000;
const MAX_SCORE     = 100;
const MIN_SCORE     = 5;
const ADMIN_PWD     = 'oryun2024';

// ── 문제 로드 ──
let questions = [];
try {
  questions = JSON.parse(fs.readFileSync(path.join(__dirname, 'questions.json'), 'utf8'));
  console.log(`✅ 문제 ${questions.length}개 로드 완료`);
} catch(e) {
  console.error('⚠️  questions.json 없음, 샘플 사용');
  questions = [{ id:1, question:'샘플 문제입니다', answer:'샘플', altAnswers:[] }];
}
let activeQuestions = [...questions];

// ── 가정 데이터 ──
// { id, name, totalScore, answeredSet: Set<qIdx>, lastElapsedMs }
const families = new Map();

// ── 퀴즈 상태 ──
// phase: 'idle' | 'question' | 'answer' | 'done'
let quizState = {
  phase:     'idle',
  qIdx:      -1,       // index in activeQuestions
  startedAt: null,
  // submissions for current question: Map familyId -> {answer, score, elapsed, correct, name}
  submissions: new Map()
};
// 퀴즈 종료 시 확정된 최종 순위 스냅샷 (families Map이 바뀌어도 보존)
let finalLeaderboardSnapshot = null;

// ── SSE 클라이언트 ──
const sseClients = new Set();

// ── 유틸 ──
function getLocalIP() {
  const nets = os.networkInterfaces();
  for (const name of Object.keys(nets))
    for (const net of nets[name])
      if (net.family === 'IPv4' && !net.internal) return net.address;
  return 'localhost';
}

function normalize(str) {
  return (str||'').toLowerCase().trim().replace(/\s+/g,'').replace(/[.,!?~·]/g,'');
}

function checkAnswer(userInput, question) {
  const norm = normalize(userInput);
  if (!norm) return false;
  if (norm === normalize(question.answer)) return true;
  if (question.altAnswers && Array.isArray(question.altAnswers))
    return question.altAnswers.some(a => normalize(a) === norm);
  return false;
}

function calcScore(elapsedMs) {
  if (elapsedMs >= TIME_LIMIT_MS) return MIN_SCORE;
  const ratio = 1 - (elapsedMs / TIME_LIMIT_MS);
  return Math.max(MIN_SCORE, Math.round(ratio * (MAX_SCORE - MIN_SCORE) + MIN_SCORE));
}

function getLeaderboard() {
  return Array.from(families.values())
    .filter(f => f.totalScore > 0 || f.answeredSet.size > 0)
    .map(f => ({
      name:      f.name,
      score:     f.totalScore,
      completed: f.answeredSet.size >= activeQuestions.length,
      progress:  f.answeredSet.size,
      total:     activeQuestions.length
    }))
    .sort((a,b) => b.score - a.score || a.lastElapsedMs - b.lastElapsedMs);
}

function buildStatePayload() {
  const q = activeQuestions[quizState.qIdx];
  return {
    type:        'quizState',
    phase:       quizState.phase,
    qIdx:        quizState.qIdx,
    question:    q ? { text: q.question, num: quizState.qIdx+1, total: activeQuestions.length } : null,
    startedAt:   quizState.startedAt,
    timeLimitMs: TIME_LIMIT_MS,
    serverNow:   Date.now(),
    answer:      (quizState.phase === 'answer' || quizState.phase === 'done') ? (q ? q.answer : null) : null,
    explanation: (quizState.phase === 'answer' || quizState.phase === 'done') ? (q ? q.explanation : null) : null,
  };
}

function buildSubmissionPayload() {
  const list = Array.from(quizState.submissions.values())
    .map(s => ({ name: s.name, correct: s.correct, score: s.score, elapsed: s.elapsed }))
    .sort((a,b) => b.score - a.score || a.elapsed - b.elapsed);
  return {
    type:    'submission',
    count:   quizState.submissions.size,
    correct: list.filter(s => s.correct).length,
    list
  };
}

function broadcast(payload) {
  const data = JSON.stringify(payload);
  sseClients.forEach(c => {
    try { c.res.write(`data: ${data}\n\n`); } catch(e) {}
  });
}

function broadcastAll() {
  broadcast(buildStatePayload());
  broadcast({ type: 'leaderboard', data: getLeaderboard() });
  broadcast(buildSubmissionPayload());
}

// ── SSE 엔드포인트 ──
app.get('/api/events', (req, res) => {
  res.setHeader('Content-Type',  'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection',    'keep-alive');
  res.flushHeaders();

  const client = { res, id: Date.now() + Math.random() };
  sseClients.add(client);

  // 연결 즉시 현재 상태 전송
  try {
    res.write(`data: ${JSON.stringify(buildStatePayload())}\n\n`);
    res.write(`data: ${JSON.stringify({ type: 'leaderboard', data: getLeaderboard() })}\n\n`);
    res.write(`data: ${JSON.stringify(buildSubmissionPayload())}\n\n`);
  } catch(e) {}

  req.on('close', () => sseClients.delete(client));
});

// ── 참가자 API ──

// 등록
app.post('/api/register', (req, res) => {
  const name = (req.body.name || '').trim();
  if (!name) return res.status(400).json({ error: '이름 필요' });

  // 같은 이름 가정이 이미 있으면 기존 세션 재연결
  const existing = Array.from(families.values()).find(f => f.name === name);
  if (existing) {
    console.log(`🔄 재연결: ${name} (점수: ${existing.totalScore})`);
    res.json({ id: existing.id, name: existing.name, totalScore: existing.totalScore, rejoined: true });
    return;
  }

  const id = 'f_' + Date.now() + '_' + Math.random().toString(36).slice(2,7);
  families.set(id, {
    id, name,
    totalScore:    0,
    lastElapsedMs: 0,
    answeredSet:   new Set()
  });
  console.log(`👫 등록: ${name} (총 ${families.size}가정)`);
  res.json({ id, name, totalScore: 0, rejoined: false });
  broadcast({ type: 'leaderboard', data: getLeaderboard() });
});

// 현재 퀴즈 상태 조회
app.get('/api/state', (req, res) => {
  res.json(buildStatePayload());
});

// 답안 제출
app.post('/api/answer', (req, res) => {
  const { familyId, answer } = req.body;
  const family = families.get(familyId);
  if (!family) return res.status(404).json({ error: '등록되지 않은 가정' });

  if (quizState.phase !== 'question')
    return res.status(400).json({ error: '문제 진행 중이 아닙니다' });

  // 이미 제출했으면 거부
  if (quizState.submissions.has(familyId))
    return res.status(400).json({ error: '이미 제출했습니다', alreadySubmitted: true });

  const elapsed = Date.now() - quizState.startedAt;
  const q       = activeQuestions[quizState.qIdx];
  const correct = checkAnswer(answer, q);
  const score   = correct ? calcScore(elapsed) : 0;

  quizState.submissions.set(familyId, {
    name: family.name, answer, score, elapsed, correct, submittedAt: Date.now()
  });

  family.totalScore    += score;
  family.lastElapsedMs += elapsed;
  family.answeredSet.add(quizState.qIdx);

  res.json({ correct, score, elapsed });
  broadcast({ type: 'leaderboard', data: getLeaderboard() });
  broadcast(buildSubmissionPayload());
});

// ── 어드민 API ──

// 전체 문제 목록 조회
app.get('/api/admin/questions', (req, res) => {
  res.json({ all: questions, active: activeQuestions });
});

// 문제 선택 적용
app.post('/api/admin/questions/select', (req, res) => {
  const { password, ids } = req.body;
  if (password !== ADMIN_PWD) return res.status(403).json({ error: '비밀번호 오류' });
  if (!ids || ids.length === 0) return res.status(400).json({ error: '최소 1개 이상 선택' });

  const idSet = new Set(ids);
  const newActive = questions.filter(q => idSet.has(q.id));
  if (newActive.length === 0) return res.status(400).json({ error: '유효한 문제 없음' });

  activeQuestions = newActive;
  // 상태 초기화
  quizState = { phase: 'idle', qIdx: -1, startedAt: null, submissions: new Map() };
  families.forEach(f => { f.totalScore = 0; f.lastElapsedMs = 0; f.answeredSet = new Set(); });
  broadcastAll();
  console.log(`📋 문제 ${activeQuestions.length}개 설정됨`);
  res.json({ success: true, count: activeQuestions.length });
});

// 문제 시작 (관리자)
app.post('/api/admin/start-question', (req, res) => {
  const { password, qIdx } = req.body;
  if (password !== ADMIN_PWD) return res.status(403).json({ error: '비밀번호 오류' });
  if (qIdx < 0 || qIdx >= activeQuestions.length)
    return res.status(400).json({ error: '잘못된 문제 번호' });

  quizState.phase      = 'question';
  quizState.qIdx       = qIdx;
  quizState.startedAt  = Date.now();
  quizState.submissions = new Map();

  broadcastAll();
  const q = activeQuestions[qIdx];
  console.log(`▶ 문제 시작 (${qIdx+1}/${activeQuestions.length}): ${q.question}`);
  res.json({ success: true, startedAt: quizState.startedAt });
});

// 정답 공개 (관리자)
app.post('/api/admin/reveal-answer', (req, res) => {
  const { password } = req.body;
  if (password !== ADMIN_PWD) return res.status(403).json({ error: '비밀번호 오류' });
  if (quizState.phase !== 'question')
    return res.status(400).json({ error: '진행 중인 문제 없음' });

  quizState.phase = 'answer';
  broadcastAll();
  console.log(`✅ 정답 공개`);
  res.json({ success: true });
});

// 퀴즈 종료
app.post('/api/admin/end-quiz', (req, res) => {
  const { password } = req.body;
  if (password !== ADMIN_PWD) return res.status(403).json({ error: '비밀번호 오류' });
  quizState.phase = 'done';
  // 종료 시점의 최종 순위를 스냅샷으로 저장
  finalLeaderboardSnapshot = getLeaderboard();
  console.log(`🎉 퀴즈 종료 — 최종 순위 ${finalLeaderboardSnapshot.length}가정`);
  broadcastAll();
  res.json({ success: true });
});

// 통계
app.get('/api/admin/stats', (req, res) => {
  // done 상태면 확정 스냅샷 사용, 아니면 실시간 계산
  const lb  = (quizState.phase === 'done' && finalLeaderboardSnapshot)
              ? finalLeaderboardSnapshot
              : getLeaderboard();
  const sub = buildSubmissionPayload();
  res.json({
    totalFamilies:     families.size,
    completedFamilies: lb.filter(f => f.completed).length,
    totalQuestions:    activeQuestions.length,
    quizPhase:         quizState.phase,
    currentQIdx:       quizState.qIdx,
    startedAt:         quizState.startedAt,          // 타이머 동기화용
    submissionCount:   sub.count,
    submissionCorrect: sub.correct,
    submissionList:    sub.list,                      // 프로젝터 화면용
    leaderboard:       lb
  });
});

// 초기화
app.post('/api/admin/reset', (req, res) => {
  const { password } = req.body;
  if (password !== ADMIN_PWD) return res.status(403).json({ error: '비밀번호 오류' });
  families.clear();
  quizState = { phase: 'idle', qIdx: -1, startedAt: null, submissions: new Map() };
  finalLeaderboardSnapshot = null;
  broadcastAll();
  console.log('🔄 초기화 완료');
  res.json({ success: true });
});

// ── 서버 시작 ──
const PORT = process.env.PORT || 3000;
const IS_CLOUD = process.env.RAILWAY_ENVIRONMENT || process.env.RENDER || process.env.FLY_APP_NAME;

server.listen(PORT, '0.0.0.0', () => {
  console.log('\n' + '='.repeat(50));
  console.log('🙏  오륜교회 성경 넌센스 퀴즈 서버 v6.0');
  console.log('='.repeat(50));
  if (IS_CLOUD) {
    console.log('☁️  클라우드 서버 실행 중');
    console.log(`📋 총 문제: ${questions.length}개`);
  } else {
    const ip = getLocalIP();
    console.log(`📱 참가자: http://${ip}:${PORT}`);
    console.log(`🖥️  관리자: http://${ip}:${PORT}/admin`);
    console.log(`📋 총 문제: ${questions.length}개`);
  }
  console.log('='.repeat(50));
});
